#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
inline int Max(int x,int y){return x>y?x:y;}
inline int Min(int x,int y){return x<y?x:y;}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10;
struct Graph
{
	int head[N],des[N],nxt[N],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
}a;;
int cpt,dfn[2][N],ans,dp[N],loc[N];
namespace SegmentTree
{
	int mx[N<<2];
	inline void update(int k){mx[k]=Max(mx[k<<1],mx[k<<1|1]);}
	inline void add(int pos,int val,int l=1,int r=cpt,int cur=1)
	{
		if(l==r){mx[cur]=Max(mx[cur],val);return;} int mid=(l+r)>>1;
		pos<=mid?add(pos,val,l,mid,cur<<1):add(pos,val,mid+1,r,cur<<1|1);update(cur); 
	}
	inline int qry(int ql,int qr,int l=1,int r=cpt,int cur=1)
	{
		if(ql<=l&&r<=qr)return mx[cur]; int mid=(l+r)>>1,res=0;
		if(ql<=mid)res=Max(res,qry(ql,qr,l,mid,cur<<1));
		if(qr>mid)res=Max(res,qry(ql,qr,mid+1,r,cur<<1|1));return res;
	}
}
namespace SuffixAutoMaton
{
	int ch[N][26],len[N],lst=1,cnt=1,fa[21][N];
	inline void ins(int c)
	{
		int p=lst,np=lst=++cnt;
		for(;p&&!ch[p][c];p=fa[0][p])ch[p][c]=np;
		if(!p)fa[0][np]=1;
		else
		{
			int v=ch[p][c];
			if(len[v]==len[p]+1)fa[0][np]=v;
			else
			{
				int nv=++cnt;
				len[nv]=len[p]+1;fa[0][nv]=fa[0][v];
				memcpy(ch[nv],ch[v],sizeof(ch[v]));
				for(;p&&ch[p][c]==v;p=fa[0][p])ch[p][c]=nv;
				fa[0][np]=fa[0][v]=nv;
			}
		}
	}
	inline void dfs1(int u=1)
	{
		dfn[0][u]=++cpt;
		rep(1,20,i)fa[i][u]=fa[i-1][fa[i-1][u]];
		grep(a,u,i)dfs1(a.des[i]);
		dfn[1][u]=cpt;
	}
}
using namespace SegmentTree;
using namespace SuffixAutoMaton;
inline int Fnd(int x,int k)
	{drep(20,0,i)if(fa[i][x]&&len[fa[i][x]]>=k)x=fa[i][x];return x;}
inline bool check(int k)
{
	int x=Fnd(loc[k],dp[k]-1),y=Fnd(loc[k-1],dp[k]-1);
	return (qry(dfn[0][x],dfn[1][x])>=dp[k]-1||qry(dfn[0][y],dfn[1][y])>=dp[k]-1);
}
char s[N];
int main()
{
	int n=read(),tmp=n;char ch=getchar();
	while(ch<'a'||ch>'z')ch=getchar();
	while(ch<='z'&&ch>='a')s[tmp--]=ch,ch=getchar();
	rep(1,n,i)ins(s[i]-'a'),loc[i]=lst;
	rep(2,cnt,i)a.ins(fa[0][i],i);dfs1();
	int j=0;rep(1,n,i)
	{
		dp[i]=dp[i-1]+1;
		while(!check(i)){++j;--dp[i];add(dfn[0][loc[j]],dp[j]);}
		ans=Max(ans,dp[i]);
	}
	printf("%d\n",ans);return 0;
}
